```typescript
type DeepReadonly<T> = T extends (infer U)[]
  ? ReadonlyArray<DeepReadonly<U>>
  : T extends Function
  ? T
  : T extends object
  ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;

// Usage example:
interface Config {
  server: {
    port: number;
    endpoints: string[];
  };
  debug: boolean;
}

const config: DeepReadonly<Config> = {
  server: {
    port: 3000,
    endpoints: ["/api"]
  },
  debug: true
};

// config.server.port = 8080; // Error: Cannot assign to 'port' because it is a read-only property.
// config.server.endpoints.push("/health"); // Error: Property 'push' does not exist on type 'readonly string[]'.
```

```typescript
type DeepReadonly<T> =
  T extends (infer U)[] ? readonly DeepReadonly<U>[] :
  T extends Function ? T :
  T extends object ? { readonly [P in keyof T]: DeepReadonly<T[P]> } :
  T;

// Usage example
interface User {
  name: string;
  address: {
    street: string;
    coordinates: number[];
  };
  tags: string[];
}

type ReadonlyUser = DeepReadonly<User>;
// ReadonlyUser['name'] is string (readonly)
// ReadonlyUser['address']['street'] is string (readonly)
// ReadonlyUser['address']['coordinates'] is readonly number[]
// ReadonlyUser['tags'] is readonly string[]
```

```typescript
type DeepReadonly<T> =
  T extends Function | null
    ? T
    : T extends object
      ? T extends Array<infer U>
        ? ReadonlyArray<DeepReadonly<U>>
        : { readonly [K in keyof T]: DeepReadonly<T[K]> }
      : T;

// Usage Example
interface Config {
  server: {
    port: number;
    hosts: string[];
  };
  features: {
    auth: {
      enabled: boolean;
      providers: string[];
    };
  };
}

const config: DeepReadonly<Config> = {
  server: {
    port: 3000,
    hosts: ["localhost"]
  },
  features: {
    auth: {
      enabled: true,
      providers: ["google"]
    }
  }
};

// All these would be compilation errors:
// config.server.port = 8080;
// config.server.hosts.push("example.com");
// config.features.auth.enabled = false;
```

type DeepReadonly<T> = {
  readonly [K in keyof T]: T[K] extends (infer U)[]
    ? readonly DeepReadonly<U>[]
    : T[K] extends object
      ? DeepReadonly<T[K]>
      : T[K];
};

// Usage example:
const obj: DeepReadonly<{ a: number; b: { c: string[] } }> = {
  a: 1,
  b: { c: ['hello'] }
};
// obj.a = 2; // Error
// obj.b.c.push('world'); // Error

